const payload = $json ?? {};
const body = payload.body && typeof payload.body === 'object' ? payload.body : payload;

const messageIdRaw =
  body.message_id ??
  body.messageId ??
  body.inbox_message_id ??
  body.data?.message_id ??
  null;

const messageId = messageIdRaw ? String(messageIdRaw).trim() : '';

const receivedAtRaw =
  body.received_at ??
  body.receivedAt ??
  body.event_at ??
  body.created_at ??
  null;

const receivedAt = receivedAtRaw ? new Date(receivedAtRaw).toISOString() : new Date().toISOString();

const webhookItem = $input.first()?.json ?? {};
const requestMetadata = {
  headers: webhookItem.headers ?? {},
  query: webhookItem.query ?? {},
  params: webhookItem.params ?? {},
  webhook_body_keys: Object.keys(body ?? {}),
};

return [
  {
    json: {
      message_id: messageId || null,
      received_at: receivedAt,
      request_metadata: requestMetadata,
      trigger_valid: Boolean(messageId),
      trigger_invalid_reason: messageId ? null : 'missing_message_id',
      scheduler_source: 'followup_scheduler_webhook',
    },
  },
];

const trigger = $('Normalize Trigger Input').item.json;
const rows = $input.all().map((item) => item.json).filter((row) => row && Object.keys(row).length > 0);
const row = rows.length > 0 ? rows[0] : null;

const normalizePlatform = (value) => {
  const v = String(value ?? '').trim().toLowerCase();
  if (['facebook', 'facebook_page', 'facebook-messenger', 'facebook_messenger', 'messenger'].includes(v)) {
    return 'page';
  }
  return v;
};

if (!trigger.trigger_valid) {
  return [
    {
      json: {
        message_valid: false,
        message_skip_reason: trigger.trigger_invalid_reason,
        should_log_skip: false,
        org_id: null,
        conversation_id: null,
        contact_id: null,
        platform: null,
        triggered_by_message_id: trigger.message_id,
        received_at: trigger.received_at,
        request_metadata: trigger.request_metadata,
      },
    },
  ];
}

if (!row || !row.id) {
  return [
    {
      json: {
        message_valid: false,
        message_skip_reason: 'inbound_message_not_found',
        should_log_skip: false,
        org_id: null,
        conversation_id: null,
        contact_id: null,
        platform: null,
        triggered_by_message_id: trigger.message_id,
        received_at: trigger.received_at,
        request_metadata: trigger.request_metadata,
      },
    },
  ];
}

const isInbound = String(row.direction ?? '').toLowerCase() === 'inbound';
const hasCore = Boolean(row.conversation_id && row.org_id);

return [
  {
    json: {
      message_valid: Boolean(isInbound && hasCore),
      message_skip_reason: isInbound && hasCore ? null : (!isInbound ? 'message_not_inbound' : 'message_missing_core_fields'),
      should_log_skip: Boolean(row.org_id && row.conversation_id && (!isInbound || !hasCore)),
      org_id: row.org_id ?? null,
      conversation_id: row.conversation_id ?? null,
      contact_id: null,
      platform: normalizePlatform(row.platform),
      triggered_by_message_id: row.id,
      latest_inbound_at: row.created_at ? new Date(row.created_at).toISOString() : trigger.received_at,
      inbound_message_created_at: row.created_at ? new Date(row.created_at).toISOString() : null,
      inbound_message: row,
      received_at: trigger.received_at,
      request_metadata: trigger.request_metadata,
    },
  },
];

const message = $('Build Message Context').item.json;
const rows = $input.all().map((item) => item.json).filter((row) => row && Object.keys(row).length > 0);
const conversation = rows.length > 0 ? rows[0] : null;

const normalizePlatform = (value) => {
  const v = String(value ?? '').trim().toLowerCase();
  if (['facebook', 'facebook_page', 'facebook-messenger', 'facebook_messenger', 'messenger'].includes(v)) {
    return 'page';
  }
  return v;
};

let reason = null;
if (!message.message_valid) {
  reason = message.message_skip_reason || 'invalid_message';
} else if (!conversation || !conversation.id) {
  reason = 'conversation_not_found';
} else if (String(conversation.status ?? '').toLowerCase() === 'closed') {
  reason = 'conversation_closed';
} else if (conversation.ai_paused === true) {
  reason = 'conversation_ai_paused';
}

const lastInboundCandidates = [message.latest_inbound_at, conversation?.last_inbound_at]
  .filter(Boolean)
  .map((value) => new Date(value).getTime())
  .filter((value) => Number.isFinite(value));

const latestInboundAt = lastInboundCandidates.length > 0
  ? new Date(Math.max(...lastInboundCandidates)).toISOString()
  : (message.latest_inbound_at || new Date().toISOString());

return [
  {
    json: {
      ...message,
      conversation_valid: reason === null,
      conversation_skip_reason: reason,
      should_log_skip: reason !== null ? Boolean(message.org_id && message.conversation_id) : false,
      contact_id: conversation?.contact_id ?? null,
      platform: normalizePlatform(conversation?.platform ?? message.platform),
      conversation: conversation ?? null,
      conversation_status: conversation?.status ?? null,
      ai_paused: conversation?.ai_paused ?? false,
      latest_inbound_at: latestInboundAt,
    },
  },
];

const conversationCtx = $('Build Conversation Context').item.json;
const contactRows = $('Load Contact').all().map((item) => item.json).filter((row) => row && row.id);
const settingsRows = $('Load Followup Settings').all().map((item) => item.json).filter((row) => row && (row.id || row.org_id));
const taskRows = $('Load Existing Followup Tasks').all().map((item) => item.json).filter((row) => row && row.id);
const accountRows = $input.all().map((item) => item.json).filter((row) => row && row.id);

const normalizePlatform = (value) => {
  const v = String(value ?? '').trim().toLowerCase();
  if (['facebook', 'facebook_page', 'facebook-messenger', 'facebook_messenger', 'messenger'].includes(v)) {
    return 'page';
  }
  return v;
};

const normalizeChannels = (value) => {
  if (Array.isArray(value)) {
    return value.map((entry) => normalizePlatform(entry)).filter(Boolean);
  }
  if (typeof value === 'string' && value.trim()) {
    return value
      .replace(/[{}]/g, '')
      .split(',')
      .map((entry) => normalizePlatform(entry.replace(/"/g, '').trim()))
      .filter(Boolean);
  }
  return [];
};

const safeInt = (value, fallback) => {
  const parsed = Number.parseInt(value, 10);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const parseTimeParts = (value, fallback) => {
  const raw = String(value ?? fallback).trim();
  const match = raw.match(/^(\d{1,2}):(\d{2})(?::(\d{2}))?$/);
  if (!match) {
    const fb = String(fallback);
    const fbMatch = fb.match(/^(\d{1,2}):(\d{2})(?::(\d{2}))?$/);
    return fbMatch ? { hour: Number(fbMatch[1]), minute: Number(fbMatch[2]), second: Number(fbMatch[3] || 0) } : { hour: 9, minute: 0, second: 0 };
  }
  return { hour: Number(match[1]), minute: Number(match[2]), second: Number(match[3] || 0) };
};

const adjustToBusinessWindowUtc = (dueAtIso, startTime, endTime) => {
  const dueDate = new Date(dueAtIso);
  const start = parseTimeParts(startTime, '09:00:00');
  const end = parseTimeParts(endTime, '18:00:00');

  let adjusted = new Date(dueDate);
  const overnight = (start.hour * 3600 + start.minute * 60 + start.second) >= (end.hour * 3600 + end.minute * 60 + end.second);

  const setToWindow = (baseDate, parts) => {
    const next = new Date(baseDate);
    next.setUTCHours(parts.hour, parts.minute, parts.second, 0);
    return next;
  };

  const windowStart = setToWindow(adjusted, start);
  let windowEnd = setToWindow(adjusted, end);
  if (overnight) {
    windowEnd.setUTCDate(windowEnd.getUTCDate() + 1);
  }

  if (!overnight) {
    if (adjusted < windowStart) {
      adjusted = windowStart;
    } else if (adjusted >= windowEnd) {
      const nextDay = new Date(windowStart);
      nextDay.setUTCDate(nextDay.getUTCDate() + 1);
      adjusted = nextDay;
    }
  } else {
    const inWindow = adjusted >= windowStart || adjusted < windowEnd;
    if (!inWindow) {
      adjusted = windowStart;
    }
  }

  return adjusted.toISOString();
};

const pickAccount = (rows) => {
  if (!rows.length) return null;
  return [...rows].sort((a, b) => {
    const aCreated = a.created_at ? new Date(a.created_at).getTime() : 0;
    const bCreated = b.created_at ? new Date(b.created_at).getTime() : 0;
    if (aCreated !== bCreated) return aCreated - bCreated;
    return String(a.id).localeCompare(String(b.id));
  })[0];
};

const settings = settingsRows.length > 0 ? settingsRows[0] : null;
const contact = contactRows.length > 0 ? contactRows[0] : null;
const account = pickAccount(accountRows);
const nowIso = new Date().toISOString();

let shouldSkip = false;
let skipReason = null;

if (!conversationCtx.message_valid) {
  shouldSkip = true;
  skipReason = conversationCtx.message_skip_reason || 'invalid_inbound_message';
} else if (!conversationCtx.conversation_valid) {
  shouldSkip = true;
  skipReason = conversationCtx.conversation_skip_reason || 'conversation_not_eligible';
}

const platform = normalizePlatform(conversationCtx.platform);
const activeChannels = normalizeChannels(settings?.active_channels);
const enabled = settings?.enabled === true;
const triggerCondition = String(settings?.trigger_condition ?? 'no_customer_reply');
const maxPerConversation = Math.max(1, safeInt(settings?.max_per_conversation, 1));
const effectiveTaskCount = taskRows.filter((task) => ['sent', 'failed'].includes(String(task.status ?? '').toLowerCase())).length;

if (!shouldSkip && !enabled) {
  shouldSkip = true;
  skipReason = settings ? 'followup_disabled' : 'followup_settings_missing';
}
if (!shouldSkip && triggerCondition !== 'no_customer_reply') {
  shouldSkip = true;
  skipReason = 'unsupported_trigger_condition';
}
if (!shouldSkip && !['whatsapp', 'page', 'instagram'].includes(platform)) {
  shouldSkip = true;
  skipReason = 'unsupported_platform';
}
if (!shouldSkip && !activeChannels.includes(platform)) {
  shouldSkip = true;
  skipReason = 'platform_not_active_in_followup_settings';
}
if (!shouldSkip && effectiveTaskCount >= maxPerConversation) {
  shouldSkip = true;
  skipReason = 'max_per_conversation_exceeded';
}
if (!shouldSkip && conversationCtx.triggered_by_message_id) {
  const dupTask = taskRows.find((task) => String(task.triggered_by_message_id ?? '') === String(conversationCtx.triggered_by_message_id));
  if (dupTask) {
    shouldSkip = true;
    skipReason = 'duplicate_trigger_message_already_scheduled';
  }
}
if (!shouldSkip && !account) {
  shouldSkip = true;
  skipReason = 'no_active_org_channel_account';
}

const scheduledOpenCount = taskRows.filter((task) => String(task.status ?? '').toLowerCase() === 'scheduled').length;
const claimedOpenCount = taskRows.filter((task) => String(task.status ?? '').toLowerCase() === 'claimed').length;
const waitingTemplateOpenCount = taskRows.filter((task) => String(task.status ?? '').toLowerCase() === 'waiting_template_approval').length;
const cancelledTaskIds = taskRows
  .filter((task) => ['scheduled', 'claimed', 'waiting_template_approval'].includes(String(task.status ?? '').toLowerCase()))
  .map((task) => task.id);

const latestInboundAt = conversationCtx.latest_inbound_at || conversationCtx.inbound_message_created_at || nowIso;
const defaultDelayMinutes = Math.max(1, safeInt(settings?.default_delay_minutes, 60));
const dueAtBase = new Date(latestInboundAt);
dueAtBase.setUTCMinutes(dueAtBase.getUTCMinutes() + defaultDelayMinutes);

let dueAt = dueAtBase.toISOString();
let dueAdjustedForBusinessHours = false;

if (!shouldSkip && settings?.business_hours_enabled === true) {
  const adjusted = adjustToBusinessWindowUtc(dueAt, settings?.business_start ?? '09:00:00', settings?.business_end ?? '18:00:00');
  dueAdjustedForBusinessHours = adjusted !== dueAt;
  dueAt = adjusted;
}

let requiresTemplate = false;
let templateName = settings?.whatsapp_template_name ?? null;
let templateLanguage = settings?.whatsapp_template_language ?? null;
let templateStatus = settings?.whatsapp_template_status ?? null;
let waitingForTemplateApproval = false;
let blockedReason = null;
let taskStatus = 'scheduled';

if (!shouldSkip && platform === 'whatsapp' && settings?.whatsapp_template_required_after_24h === true) {
  const dueMs = new Date(dueAt).getTime();
  const inboundMs = new Date(latestInboundAt).getTime();
  requiresTemplate = Number.isFinite(dueMs) && Number.isFinite(inboundMs) && (dueMs - inboundMs) > (24 * 60 * 60 * 1000);
  if (requiresTemplate) {
    const approved = String(templateStatus ?? '').trim().toLowerCase() === 'approved';
    if (!templateName || !templateLanguage) {
      waitingForTemplateApproval = true;
      blockedReason = 'missing_whatsapp_template_assignment';
      taskStatus = 'waiting_template_approval';
    } else if (!approved) {
      waitingForTemplateApproval = true;
      blockedReason = 'whatsapp_template_not_approved';
      taskStatus = 'waiting_template_approval';
    }
  }
}

const scheduleSkipLogDetails = {
  reason: skipReason,
  platform,
  message_id: conversationCtx.triggered_by_message_id,
  conversation_id: conversationCtx.conversation_id,
  org_id: conversationCtx.org_id,
  enabled,
  trigger_condition: triggerCondition,
  active_channels: activeChannels,
  effective_task_count: effectiveTaskCount,
  max_per_conversation: maxPerConversation,
};

const cancelledPreviousOpenLogDetails = {
  cancelled_task_ids: cancelledTaskIds,
  cancelled_counts: {
    scheduled: scheduledOpenCount,
    claimed: claimedOpenCount,
    waiting_template_approval: waitingTemplateOpenCount,
  },
  reason: 'new_inbound_message_for_conversation',
  message_id: conversationCtx.triggered_by_message_id,
  conversation_id: conversationCtx.conversation_id,
};

const scheduledLogDetails = {
  due_at: dueAt,
  requires_template: requiresTemplate,
  template_name: templateName,
  template_language: templateLanguage,
  template_status: templateStatus,
  latest_inbound_at: latestInboundAt,
  platform,
  message_id: conversationCtx.triggered_by_message_id,
  conversation_id: conversationCtx.conversation_id,
  org_channel_account_id: account?.id ?? null,
};

const templateRequiredLogDetails = {
  due_at: dueAt,
  latest_inbound_at: latestInboundAt,
  template_name: templateName,
  template_language: templateLanguage,
  template_status: templateStatus,
  blocked_reason: blockedReason,
  platform,
  conversation_id: conversationCtx.conversation_id,
  message_id: conversationCtx.triggered_by_message_id,
};

const waitingTemplateLogDetails = {
  due_at: dueAt,
  waiting_for_template_approval: waitingForTemplateApproval,
  blocked_reason: blockedReason,
  template_name: templateName,
  template_language: templateLanguage,
  template_status: templateStatus,
};

const deferredBusinessHoursLogDetails = {
  original_due_at: dueAtBase.toISOString(),
  adjusted_due_at: dueAt,
  business_start: settings?.business_start ?? '09:00:00',
  business_end: settings?.business_end ?? '18:00:00',
  policy_timezone: 'UTC',
};

return [
  {
    json: {
      org_id: conversationCtx.org_id,
      conversation_id: conversationCtx.conversation_id,
      contact_id: conversationCtx.contact_id ?? contact?.id ?? null,
      platform,
      triggered_by_message_id: conversationCtx.triggered_by_message_id,
      latest_inbound_at: latestInboundAt,
      org_channel_account_id: account?.id ?? null,
      should_skip: shouldSkip,
      should_log_skip: shouldSkip && Boolean(conversationCtx.org_id && conversationCtx.conversation_id),
      skip_reason: skipReason,
      has_scheduled_open: scheduledOpenCount > 0,
      has_claimed_open: claimedOpenCount > 0,
      has_waiting_template_open: waitingTemplateOpenCount > 0,
      any_open_to_cancel: cancelledTaskIds.length > 0,
      due_at: dueAt,
      due_adjusted_for_business_hours: dueAdjustedForBusinessHours,
      requires_template: requiresTemplate,
      template_name: templateName,
      template_language: templateLanguage,
      template_status: templateStatus,
      waiting_for_template_approval: waitingForTemplateApproval,
      blocked_reason: blockedReason,
      task_status: taskStatus,
      schedule_skip_log_details: scheduleSkipLogDetails,
      cancelled_previous_open_log_details: cancelledPreviousOpenLogDetails,
      scheduled_log_details: scheduledLogDetails,
      template_required_log_details: templateRequiredLogDetails,
      waiting_template_log_details: waitingTemplateLogDetails,
      deferred_business_hours_log_details: deferredBusinessHoursLogDetails,
      created_at: nowIso,
      updated_at: nowIso,
      claimed_at: null,
      sent_at: null,
      cancelled_at: null,
      failed_at: null,
      resolved_message: null,
      resolved_language: null,
      provider_message_id: null,
      provider_response: null,
      error_message: null,
      notification_state: null,
    },
  },
];

const ctx = $input.all()[0]?.json ?? {};
return [
  {
    json: {
      org_id: ctx.org_id ?? null,
      conversation_id: ctx.conversation_id ?? null,
      contact_id: ctx.contact_id ?? null,
      created_at: new Date().toISOString(),
      details: {
        reason: ctx.message_skip_reason ?? 'invalid_message',
        platform: ctx.platform ?? null,
        message_id: ctx.triggered_by_message_id ?? null,
        conversation_id: ctx.conversation_id ?? null,
      },
    },
  },
];

const ctx = $input.all()[0]?.json ?? {};
return [
  {
    json: {
      org_id: ctx.org_id ?? null,
      conversation_id: ctx.conversation_id ?? null,
      contact_id: ctx.contact_id ?? null,
      created_at: new Date().toISOString(),
      details: {
        reason: ctx.conversation_skip_reason ?? 'conversation_not_eligible',
        platform: ctx.platform ?? null,
        message_id: ctx.triggered_by_message_id ?? null,
        conversation_id: ctx.conversation_id ?? null,
      },
    },
  },
];
